import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Counter     from '../components/Counter/Counter';
import SelectField from '../components/SelectField/SelectField';
import InputField  from '../components/InputField/InputField';
import { usePredictor } from '../hooks/usePredictor';
import { predictPrice } from '../services/api';
import { LOCATIONS, AREA_TYPES, AVAILABILITY } from '../constants/options';
import styles from './PredictorPage.module.css';

function PredictorPage() {
  const navigate = useNavigate();
  const {
    form, loading, error,
    setField, handleReset,
  } = usePredictor();
  const [submitError, setSubmitError] = useState('');
  const [submitLoading, setSubmitLoading] = useState(false);

  const onSubmit = async (e) => {
    e.preventDefault();

    // Validate
    const sqft = Number(form.total_sqft);
    if (!form.total_sqft || isNaN(sqft)) {
      setSubmitError('Please enter the total sqft.');
      return;
    }
    if (sqft < 300) {
      setSubmitError('Sqft must be at least 300.');
      return;
    }
    if (sqft > 10000) {
      setSubmitError('Sqft value seems too high.');
      return;
    }
    if (form.bath > form.bhk + 2) {
      setSubmitError('Too many bathrooms for the selected BHK.');
      return;
    }

    // Prepare the data to send
    const payload = {
      location: form.location,
      area_type: form.area_type,
      availability: form.availability,
      total_sqft: sqft,
      bhk: form.bhk,
      bath: form.bath,
      balcony: form.balcony,
    };

    console.log('Form data being sent:', payload);

    // Call the API directly
    setSubmitError('');
    setSubmitLoading(true);

    try {
      const data = await predictPrice(payload);

      console.log('Prediction result:', data);

      if (data.success) {
        // Navigate to results page with form data and price
        navigate('/results', { 
          state: { 
            formData: payload, 
            price: data.price 
          } 
        });
      } else {
        setSubmitError(data.error || 'Prediction failed. Please try again.');
      }
    } catch (err) {
      console.error('Submission error:', err);
      setSubmitError('Network error. Please check if backend is running.');
    }

    setSubmitLoading(false);
  };

  return (
    <div className={styles.page}>
      <div className={styles.wrapper}>

        {/* ── Header ───────────────────────────────────────────── */}
        <header className={styles.header}>
          <div className={styles.headerBadge}>🏡 Kharar / Mohali — Real Estate</div>
          <h1 className={styles.title}>
            Find Your Dream
            <span className={styles.accent}> Home</span>
          </h1>
          <p className={styles.subtitle}>
            AI-Powered Price Predictions with Gradient Boosting
          </p>
          <div className={styles.stats}>
            <div className={styles.statItem}>
              <span className={styles.statNumber}>0.94</span>
              <span className={styles.statLabel}>Model R² Score</span>
            </div>
            <div className={styles.statDivider}></div>
            <div className={styles.statItem}>
              <span className={styles.statNumber}>80K+</span>
              <span className={styles.statLabel}>Training Records</span>
            </div>
            <div className={styles.statDivider}></div>
            <div className={styles.statItem}>
              <span className={styles.statNumber}>6+</span>
              <span className={styles.statLabel}>Property Options</span>
            </div>
          </div>
        </header>

        {/* ── Form Card ────────────────────────────────────────── */}
        <div className={styles.card}>
          <form onSubmit={onSubmit} noValidate>

            {/* Section 1 — Location */}
            <section className={styles.section}>
              <h2 className={styles.sectionLabel}>Location</h2>
              <SelectField
                label="Location"
                name="location"
                value={form.location}
                onChange={v => setField('location', v)}
                options={LOCATIONS}
              />
            </section>

            {/* Section 2 — Property Specs */}
            <section className={styles.section}>
              <h2 className={styles.sectionLabel}>Property Specs</h2>
              <div className={styles.grid3}>
                <div className={styles.counterWrap}>
                  <p className={styles.counterLabel}>BHK</p>
                  <Counter
                    value={form.bhk}
                    onChange={v => setField('bhk', v)}
                    min={1} max={5}
                  />
                </div>
                <div className={styles.counterWrap}>
                  <p className={styles.counterLabel}>Bathrooms</p>
                  <Counter
                    value={form.bath}
                    onChange={v => setField('bath', v)}
                    min={1} max={5}
                  />
                </div>
                <div className={styles.counterWrap}>
                  <p className={styles.counterLabel}>Balconies</p>
                  <Counter
                    value={form.balcony}
                    onChange={v => setField('balcony', v)}
                    min={0} max={4}
                  />
                </div>
              </div>
            </section>

            {/* Section 3 — Area & Type */}
            <section className={styles.section}>
              <h2 className={styles.sectionLabel}>Area & Type</h2>
              <div className={styles.grid2}>
                <InputField
                  label="Total Sqft"
                  name="total_sqft"
                  type="number"
                  value={form.total_sqft}
                  onChange={v => setField('total_sqft', v)}
                  placeholder="e.g. 1500"
                  min={300}
                  max={10000}
                />
                <SelectField
                  label="Area Type"
                  name="area_type"
                  value={form.area_type}
                  onChange={v => setField('area_type', v)}
                  options={AREA_TYPES}
                />
              </div>
              <div className={styles.singleRow}>
                <SelectField
                  label="Availability"
                  name="availability"
                  value={form.availability}
                  onChange={v => setField('availability', v)}
                  options={AVAILABILITY}
                />
              </div>
            </section>

            {/* Validation error */}
            {(error || submitError) && <p className={styles.errorMsg}>{error || submitError}</p>}

            {/* Actions */}
            <div className={styles.actions}>
              <button
                type="submit"
                className={styles.btnPredict}
                disabled={submitLoading}
              >
                {submitLoading
                  ? <><span className={styles.spinner} /> Finding Properties…</>
                  : '🔍 View Available Properties'
                }
              </button>
              <button
                type="button"
                className={styles.btnReset}
                onClick={handleReset}
              >
                Reset
              </button>
            </div>

          </form>
        </div>

        {/* ── Footer ───────────────────────────────────────────── */}
        <footer className={styles.footer}>
          React + Flask &nbsp;·&nbsp; Kharar / Mohali Real Estate &nbsp;·&nbsp; Model R² 0.94
        </footer>

      </div>
    </div>
  );
}

export default PredictorPage;
